const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

interface Item {
  type: string;
}

interface QuoteStep {
  items: Item[];
}

export const quote = (
  customer: unknown,
  step: QuoteStep,
  quoteIndex: number,
): number => {
  let base = 0;
  for (const item of step.items) {
    if (item.type === "sword") base += 100;
  }
  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
  return withFirstInsurance + PROCESSING_FEE;
};

