const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

interface Item {
  type: string;
}

interface QuoteStep {
  items: Item[];
}

// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
// floating-point artifacts (e.g. 197.49999999) so we don't round a value
// that is only spuriously above a whole number.
const roundUpInMHPCOsFavor = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

export const quote = (
  customer: unknown,
  step: QuoteStep,
  quoteIndex: number,
): number => {
  const basePremium = step.items.reduce(
    (sum, item) => sum + basePremiumForItem(item),
    0,
  );
  const withFirstInsurance = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
  const total = withFirstInsurance + PROCESSING_FEE;
  return roundUpInMHPCOsFavor(total);
};

export const claim = (...args: unknown[]): unknown => {
  return undefined; // Intentionally not implemented
};

