import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office — quote (premium)", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (processing fee only)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, { op: "quote", items: [] }, 0)).toBe(5);
  });

  // --- Single main item base premiums (+ fee, first insurance per item) ---
  // Newcomer, single plain item: base + 10% first insurance + 5 fee.
  it("single sword (newcomer) → 100 + 10 first + 5 fee = 115 G", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
        0,
      ),
    ).toBe(115);
  });
  it("single amulet (newcomer) → 60 + 6 first + 5 fee = 71 G", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] },
        0,
      ),
    ).toBe(71);
  });
  it("single staff (newcomer) → 80 + 8 first + 5 fee = 93 G", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] },
        0,
      ),
    ).toBe(93);
  });
  it("single potion (newcomer) → 40 + 4 first + 5 fee = 49 G", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] },
        0,
      ),
    ).toBe(49);
  });

  // --- Components and building blocks (base premiums per spec examples) ---
  it("1 rune (newcomer) → base 25 → premium 33 G (25×1.1+5=32.5→33)", () => {
    expect(
      quote({ yearsWithMHPCO: 0 }, { op: "quote", items: [{ type: "rune" }] }, 0),
    ).toBe(33);
  });
  it("2 runes (newcomer) → base 50 → premium 60 G (no block)", () => {
    expect(
      quote({ yearsWithMHPCO: 0 }, { op: "quote", items: [{ type: "rune" }, { type: "rune" }] }, 0),
    ).toBe(60);
  });
  it("3 runes (newcomer) → base 60 block → premium 71 G", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
        0,
      ),
    ).toBe(71);
  });
  it.todo("4 runes → base premium 100 G (no block — block requires exactly 3)");
  it.todo("7 runes → base premium 175 G");

  // --- "Alike" components (❓ resolved: alike = same type) ---
  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");

  // --- Item-specific modifiers in isolation ---
  it.todo("cursed sword → base 100 + 50% curse surcharge on the item");
  it.todo("sword enchantment 5 → +30% high-enchantment surcharge (threshold inclusive)");
  it.todo("sword enchantment 4 → no high-enchantment surcharge");
  it.todo("sword enchantment 5 and cursed → both surcharges apply");

  // --- Policy-wide modifiers in isolation ---
  it.todo("loyalty: customer with exactly 2 years → 20% loyalty discount applies");
  it.todo("follow-up: second+ quote in scenario → 15% follow-up discount applies");

  // --- Modifier scope on multi-item policies (❓ resolved) ---
  it.todo("cursed sword + plain amulet → policy base 160, curse adds 50 (on sword only) → 210 before fee/policy modifiers");

  // --- Rounding (MHPCO's favor) ---
  it.todo("premium yielding 197.5 → rounded UP to 198 G");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → premium 160 G");
});

describe("MHPCO Claim Office — claim (payout)", () => {
  // --- Standard reimbursement (no special clauses) ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 G (500 − 100 deductible)");
  it.todo("rune (value 250), damage 200 → payout 100 G (200 − 100, no special clause)");

  // --- Enchantment threshold vs dragon material ---
  it.todo("dragon sword, ench 8, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon sword, ench 9, damage 1000 → payout 400 G (50% wins, then deductible)");
  it.todo("dragon sword, ench 5, damage 800 → payout 700 G (dragon full, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 G (50% then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // --- Multiple items of the same type ---
  it.todo("two swords insured → insurance sum 2000, two sword damages each get own deductible");
  it.todo("more sword damages than swords insured → claim rejected (error)");

  // --- Cap exhaustion across successive claims ---
  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword (cap 2000): second claim 1500 → payout 600, remainingCap 0 (reduced to remaining cap)");

  // --- Cap basis ---
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value; premium modifiers do not raise cap)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 (block discount does not affect insurance sum)");

  // --- Rounding (payout rounded down) ---
  it.todo("payout yielding 350.5 → rounded DOWN to 350 G");

  // --- Claim error cases ---
  it.todo("damage to item not in policy → claim rejected (error)");
  it.todo("damage with negative amount → claim rejected (error)");
});

describe("MHPCO Claim Office — unknown item / errors", () => {
  it.todo("quote with unknown item type → throws (CLI exits non-zero)");
});

