interface Item {
  type: string;
}

interface QuoteStep {
  items: Item[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = ["rune", "moonstone"];
const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.includes(item.type);

const isMainItem = (item: Item): boolean => !isComponent(item);

// A group of exactly BLOCK_SIZE alike components is priced at the discounted
// BLOCK_PREMIUM; any other count is priced per component.
const componentGroupBasePremium = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;

// The first insurance always applies; every policy carries its surcharge.
const withFirstInsuranceSurcharge = (basePremium: number): number =>
  basePremium * (1 + FIRST_INSURANCE_SURCHARGE);

// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
// floating-point artifacts (e.g. 197.49999999) so we don't round a value
// that is only spuriously above a whole number.
const roundUpInMHPCOsFavor = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

// Each main item is priced on its own.
const mainItemsBasePremium = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

// Components are grouped by type, and each group is block-priced.
const componentsBasePremium = (components: Item[]): number =>
  [...countByType(components).values()].reduce(
    (sum, count) => sum + componentGroupBasePremium(count),
    0,
  );

export const quote = (
  customer: unknown,
  step: QuoteStep,
  quoteIndex: number,
): number => {
  const mainItems = step.items.filter(isMainItem);
  const components = step.items.filter(isComponent);

  const policyBasePremium =
    mainItemsBasePremium(mainItems) + componentsBasePremium(components);
  const total = withFirstInsuranceSurcharge(policyBasePremium) + PROCESSING_FEE;
  return roundUpInMHPCOsFavor(total);
};

export const claim = (...args: unknown[]): unknown => {
  return undefined; // Intentionally not implemented
};

