1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  items: Item[];
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_SURCHARGE = 0.1;
13	const CURSE_SURCHARGE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	
17	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_TYPES = ["rune", "moonstone"];
25	const COMPONENT_PREMIUM = 25;
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	// Sum `valueOf` applied to each element of an iterable.
30	const sumOf = <T>(values: Iterable<T>, valueOf: (value: T) => number): number => {
31	  let sum = 0;
32	  for (const value of values) sum += valueOf(value);
33	  return sum;
34	};
35	
36	const isComponent = (item: Item): boolean =>
37	  COMPONENT_TYPES.includes(item.type);
38	
39	const isMainItem = (item: Item): boolean => !isComponent(item);
40	
41	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
42	// BLOCK_PREMIUM; any other count is priced per component.
43	const componentGroupBasePremium = (count: number): number =>
44	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
45	
46	// An item-specific surcharge adds `rate` of the item's base premium when its
47	// condition holds, and nothing otherwise.
48	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
49	  applies ? rate * basePremiumForItem(item) : 0;
50	
51	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
52	const curseSurcharge = (item: Item): number =>
53	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
54	
55	// Highly enchanted items (enchantment at or above the threshold) add a
56	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
57	const highEnchantmentSurcharge = (item: Item): number =>
58	  surchargeWhen(
