const DEDUCTIBLE = 100;
const ENCHANTMENT_HALF_THRESHOLD = 8;
const HALF_REIMBURSEMENT = 0.5;

// What MHPCO reimburses for a single damage, before the deductible: items at or
// above the half-reimbursement enchantment threshold are reimbursed at half the
// damage amount; otherwise the full amount.
const reimbursedAmount = (item: Item | undefined, amount: number): number =>
  (item?.enchantment ?? 0) >= ENCHANTMENT_HALF_THRESHOLD
    ? HALF_REIMBURSEMENT * amount
    : amount;

export const claim = (policyItems: Item[], incident: Incident): ClaimResult => {
  const payout = sumOf(incident.damages, (damage) => {
    const item = policyItems.find((i) => i.type === damage.itemType);
    return reimbursedAmount(item, damage.amount) - DEDUCTIBLE;
  });
  return { payout, remainingCap: 0 };
};

