// The net payout for a single damage: what MHPCO reimburses for the damaged
// item, less the per-damage deductible.
const netPayoutForDamage = (policyItems: Item[], damage: Damage): number => {
  const item = policyItems.find((i) => i.type === damage.itemType);
  return reimbursedAmount(item, damage.amount) - DEDUCTIBLE;
};

export const claim = (policyItems: Item[], incident: Incident): ClaimResult => {
  const cap = payoutCap(policyItems);
  const payout = sumOf(incident.damages, (damage) =>
    netPayoutForDamage(policyItems, damage),
  );
  return { payout, remainingCap: cap - payout };
};

